// TypeScript backend ‚Äî AST ‚Üí typed `.ts` source (ADR 0026; Axis A of
// docs/TS_DIALECT.md). Not a fresh emitter: it orchestrates the two backends we
// already have. Types come from `dts.ts` (the `.d.ts` writer's HM-type ‚Üí TS-type
// machinery, reused inline); values come from `codegen.ts` via its `annotate`
// and `annotateCtor` hooks, which splice each binding's / ctor factory's type in.
//
// Runtime helpers (`_curry`, `add`, ‚Ä¶) are imported from the typed runtime module
// (`src/runtime.ts`, generated by scripts/gen-runtime.ts) instead of inlined ‚Äî so
// the emitted `.ts` is strict-`tsc`-clean end to end. The import specifier is
// configurable (`runtimeImport`), defaulting to the published package name.
import { isErr, ok, type Result } from "@onrails/result";
import type { Expr, Program } from "./ast";
import { codegen, collectRuntimeDeps } from "./codegen";
import { toTypedProgram } from "./compile";
import {
  aliasTsDecl,
  bindingTsType,
  builtinDeclsIn,
  ctorFactoryTs,
  genericLambdaParams,
  guardParamTs,
  lambdaParamTypesTs,
  referencedBuiltinTypeDecls,
  typeDecl,
} from "./dts";
import type { AlangError } from "./errors";
import type { Env, Scheme, TypeAt } from "./infer";
import { preludeNamespaces } from "./prelude";
import type { Span } from "./span";
import type { AliasDef } from "./types";

export type CodegenTsOptions = { runtimeImport?: string };

export const DEFAULT_RUNTIME_IMPORT = "@alang/runtime";

// The inference result + cross-module wiring a module needs to emit its `.ts`.
// A single file has empty `importLines`/`importedKeys`; a module in a graph
// (build --emit=ts) supplies its dependency imports and destructure keys.
export type TsEmitContext = {
  env: Env;
  aliases: AliasDef[];
  types: TypeAt[];
  importedKeys: Map<string, string[]>;
  importLines: string[];
  runtimeImport: string;
};

// Emit one module's typed `.ts` from a prepared context. Type header (referenced
// builtin unions + this module's own `type` decls as `export type`), then any
// cross-module imports, then the runtime import, then the codegen body with
// per-binding / per-ctor annotations and pipe flattening. Pure ‚Äî inference and
// import resolution happen in the caller (`codegenTs` for a file, the graph
// driver for `build --emit=ts`).
export const emitTsModule = (prog: Program, ctx: TsEmitContext): string => {
  const aliasByName = new Map(ctx.aliases.map((a) => [a.name, a]));
  const typeHeader = [
    ...referencedBuiltinTypeDecls(prog, (n) => ctx.env.get(n)),
    ...prog.stmts.flatMap((s) => {
      if (s.kind !== "type") return [];
      const a = aliasByName.get(s.name);
      return [a ? aliasTsDecl(a) : typeDecl(s.name, s.params, s.ctors)];
    }),
  ];

  const deps = collectRuntimeDeps(prog);
  const runtimeLine = deps.length
    ? `import { ${deps.join(", ")} } from ${JSON.stringify(ctx.runtimeImport)};`
    : "";

  // Per-node inferred types, keyed by span, for annotating lambda params below.
  const typeAt = new Map(ctx.types.map((t) => [`${t.span.start}:${t.span.end}`, t.type]));

  // Annotate function-valued top-level lets. Lambda params are where TS inference
  // is weakest (bare `(x) => ‚Ä¶` infers `any` under strict) and where the
  // generic/nominal signature pays off. A non-function polymorphic binding has no
  // place to bind generics ‚Äî dts renders its escaped vars as `unknown` ‚Äî so
  // annotating it would be worse than TS's own inference; skip it.
  const annotate = (name: string, value: Expr): string | null => {
    if (value.kind !== "lambda" || name.startsWith("$")) return null;
    const sc = ctx.env.get(name);
    return sc ? `: ${bindingTsType(sc, value, ctx.aliases)}` : null;
  };

  // The value lambda of each GENERIC top-level function binding, keyed by span ‚Üí
  // its scheme (ADR 0032). Its params are annotated in full and the arrow carries
  // a generic head, so polymorphic inner params name the letters instead of being
  // erased to `any`/`unknown` by `_curry`.
  const genericBindingLambda = new Map<string, Scheme>();
  for (const s of prog.stmts) {
    if (s.kind !== "let" || s.value.kind !== "lambda" || s.name.startsWith("$")) continue;
    const sc = ctx.env.get(s.name);
    // Type vars OR row vars: a row-poly binding (`st => {...st}`, no type vars)
    // still needs the generic head so its open-row params emit `{‚Ä¶} & R` under
    // a scoped `<R>` (ADR 0034), not a closed record dropping the row var.
    if (sc && (sc.vars.length > 0 || sc.rvars.length > 0))
      genericBindingLambda.set(`${s.value.span.start}:${s.value.span.end}`, sc);
  }

  // Annotate each lambda's params from its inferred curried type (ADR 0028) ‚Äî
  // concrete types only, no generic head; generic params stay bare (typed
  // contextually by tsc). Exception (ADR 0032): a generic binding's value lambda
  // gets a generic head + ALL params annotated, so its polymorphic inner params
  // name the letters rather than falling to `any`/`unknown` through `_curry`.
  const annotateParams = (span: Span, arity: number) => {
    const key = `${span.start}:${span.end}`;
    const sc = genericBindingLambda.get(key);
    const g = sc ? genericLambdaParams(sc, arity, ctx.aliases) : null;
    if (g) return g;
    const t = typeAt.get(key);
    return { generics: "", params: t ? lambdaParamTypesTs(t, arity, ctx.aliases) : [] };
  };

  // The concrete type each guard-form arm narrows FROM (ADR 0031). codegen turns
  // it into a type-predicate guard so nested-pattern handlers narrow ‚Äî ts-pattern
  // only refines handler input for `x is U` guards, not boolean ones.
  const guardBaseType = (scrutinee: Expr) => {
    const t = typeAt.get(`${scrutinee.span.start}:${scrutinee.span.end}`);
    return t ? guardParamTs(t, ctx.aliases) : null;
  };

  // Type each variant's ctor factories (return the variant type, params from the
  // ctor's field TypeExprs ‚Äî ADR 0015) so `Circle(2)` is a `Shape`, not `any`.
  const body = codegen(prog, ctx.importedKeys, {
    runtime: false,
    annotate,
    annotateParams,
    guardBaseType,
    annotateCtor: (s, c) => ctorFactoryTs(s.name, s.params, c),
    flattenPipe: true,
    moduleExt: "", // `import ‚Ä¶ from "./mod"` ‚Äî tsc resolves to the sibling `.ts`
  });

  // A guard predicate can name a builtin variant (`Option`) the header didn't
  // already emit ‚Äî inject its decl now that the body text exists (ADR 0031).
  const header = [...builtinDeclsIn(body, typeHeader.join("\n")), ...typeHeader];

  const parts = [header.join("\n"), ctx.importLines.join("\n"), runtimeLine, body].filter(
    (p) => p !== "",
  );
  return `${parts.join("\n\n")}\n`;
};

// Compile a single `.al` source to a typed `.ts` module (CLI `alang ts`). Open
// world, no cross-module imports resolved ‚Äî a file that imports from another
// module won't typecheck alone; use `build --emit=ts` for a graph.
export const codegenTs = (src: string, opts: CodegenTsOptions = {}): Result<string, AlangError> => {
  const r = toTypedProgram(src, { open: true, namespaces: preludeNamespaces });
  if (isErr(r)) return r;
  const { prog, res } = r.value;
  return ok(
    emitTsModule(prog, {
      env: res.env,
      aliases: res.aliases,
      types: res.types,
      importedKeys: new Map(),
      importLines: [],
      runtimeImport: opts.runtimeImport ?? DEFAULT_RUNTIME_IMPORT,
    }),
  );
};
